import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const statusColors = {
  'todo': '#fef3c7',
  'in-progress': '#dbeafe',
  'done': '#dcfce7',
};

const Tasks = () => {
  const { id: projectId } = useParams();
  const [tasks, setTasks] = useState([]);
  const [members, setMembers] = useState([]); // project members list
  const [form, setForm] = useState({
    title: '',
    description: '',
    dueDate: '',
    priority: 'medium',
    assignedTo: '',
  });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const { user } = useAuth();

  useEffect(() => {
    fetchTasks();
    fetchMembers();
  }, []);

  const fetchTasks = async () => {
    try {
      const { data } = await API.get(`/tasks?project=${projectId}`);
      setTasks(data.tasks);
    } catch (err) {
      setError('Failed to load tasks');
    }
  };

  // Fetch all users to populate assign dropdown
  const fetchMembers = async () => {
    try {
      const { data } = await API.get('/auth/users');
      setMembers(data.users);
    } catch (err) {
      console.error('Could not load members');
    }
  };

  const handleCreate = async () => {
    if (!form.title) return setError('Task title is required');
    setError('');
    try {
      await API.post('/tasks', { ...form, project: projectId });
      setForm({ title: '', description: '', dueDate: '', priority: 'medium', assignedTo: '' });
      setSuccess('Task created successfully!');
      setTimeout(() => setSuccess(''), 3000);
      fetchTasks();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create task');
    }
  };

  const handleStatusChange = async (taskId, newStatus) => {
    try {
      await API.put(`/tasks/${taskId}`, { status: newStatus });
      fetchTasks();
    } catch (err) {
      setError('Failed to update status');
    }
  };

  const handleAssignChange = async (taskId, newAssignee) => {
    try {
      await API.put(`/tasks/${taskId}`, { assignedTo: newAssignee });
      fetchTasks();
    } catch (err) {
      setError('Failed to reassign task');
    }
  };

  const handleDelete = async (taskId) => {
    if (!window.confirm('Delete this task?')) return;
    try {
      await API.delete(`/tasks/${taskId}`);
      fetchTasks();
    } catch (err) {
      setError('Failed to delete task');
    }
  };

  const unassigned = tasks.filter(t => !t.assignedTo).length;
  const assigned = tasks.filter(t => t.assignedTo).length;

  return (
    <div style={styles.container}>
      <h2 style={styles.heading}>✅ Tasks</h2>

      {/* Admin summary bar */}
      {user?.role === 'admin' && (
        <div style={styles.summaryBar}>
          <div style={styles.summaryItem}>
            <span style={styles.summaryNum}>{tasks.length}</span>
            <span style={styles.summaryLabel}>Total</span>
          </div>
          <div style={styles.summaryItem}>
            <span style={{ ...styles.summaryNum, color: '#f59e0b' }}>{unassigned}</span>
            <span style={styles.summaryLabel}>Unassigned</span>
          </div>
          <div style={styles.summaryItem}>
            <span style={{ ...styles.summaryNum, color: '#10b981' }}>{assigned}</span>
            <span style={styles.summaryLabel}>Assigned</span>
          </div>
          <div style={styles.summaryItem}>
            <span style={{ ...styles.summaryNum, color: '#8b5cf6' }}>
              {tasks.filter(t => t.status === 'done').length}
            </span>
            <span style={styles.summaryLabel}>Done</span>
          </div>
        </div>
      )}

      {/* Admin: Create task form */}
      {user?.role === 'admin' && (
        <div style={styles.form}>
          <h3 style={styles.formTitle}>➕ Add New Task</h3>
          {error && <div style={styles.error}>{error}</div>}
          {success && <div style={styles.success}>{success}</div>}

          <div style={styles.formGrid}>
            <input style={styles.input} placeholder="Task Title *"
              value={form.title}
              onChange={(e) => setForm({ ...form, title: e.target.value })} />
            <input style={styles.input} placeholder="Description"
              value={form.description}
              onChange={(e) => setForm({ ...form, description: e.target.value })} />
            <input style={styles.input} type="date"
              value={form.dueDate}
              onChange={(e) => setForm({ ...form, dueDate: e.target.value })} />
            <select style={styles.input} value={form.priority}
              onChange={(e) => setForm({ ...form, priority: e.target.value })}>
              <option value="low">🟢 Low Priority</option>
              <option value="medium">🟡 Medium Priority</option>
              <option value="high">🔴 High Priority</option>
            </select>

            {/* Assign to member dropdown */}
            <select style={styles.input} value={form.assignedTo}
              onChange={(e) => setForm({ ...form, assignedTo: e.target.value })}>
              <option value="">👤 Assign to member (optional)</option>
              {members.map(m => (
                <option key={m._id} value={m._id}>
                  {m.name} ({m.role})
                </option>
              ))}
            </select>
          </div>

          <button style={styles.button} onClick={handleCreate}>
            + Create Task
          </button>
        </div>
      )}

      {/* Task list */}
      <div style={styles.list}>
        {tasks.map((task) => (
          <div key={task._id} style={{
            ...styles.card,
            borderLeft: `4px solid ${
              task.priority === 'high' ? '#ef4444' :
              task.priority === 'medium' ? '#f59e0b' : '#10b981'
            }`,
            backgroundColor: statusColors[task.status] || 'white',
          }}>
            <div style={styles.cardHeader}>
              <div>
                <h3 style={styles.cardTitle}>{task.title}</h3>
                {task.description && (
                  <p style={styles.desc}>{task.description}</p>
                )}
              </div>
              <div style={styles.cardActions}>
                <span style={{
                  ...styles.priorityBadge,
                  background: task.priority === 'high' ? '#fee2e2' :
                    task.priority === 'medium' ? '#fef3c7' : '#dcfce7',
                  color: task.priority === 'high' ? '#dc2626' :
                    task.priority === 'medium' ? '#d97706' : '#16a34a',
                }}>
                  {task.priority}
                </span>
                {user?.role === 'admin' && (
                  <button style={styles.deleteBtn}
                    onClick={() => handleDelete(task._id)}>🗑️</button>
                )}
              </div>
            </div>

            {task.dueDate && (
              <p style={{
                ...styles.due,
                color: new Date(task.dueDate) < new Date() && task.status !== 'done'
                  ? '#ef4444' : '#f59e0b'
              }}>
                📅 Due: {new Date(task.dueDate).toLocaleDateString()}
                {new Date(task.dueDate) < new Date() && task.status !== 'done'
                  ? ' ⚠️ Overdue!' : ''}
              </p>
            )}

            {/* Assigned to — admin can reassign inline */}
            <div style={styles.assignRow}>
              <span style={styles.assignLabel}>👤 Assigned to:</span>
              {user?.role === 'admin' ? (
                <select
                  style={styles.assignSelect}
                  value={task.assignedTo?._id || ''}
                  onChange={(e) => handleAssignChange(task._id, e.target.value)}
                >
                  <option value="">— Unassigned —</option>
                  {members.map(m => (
                    <option key={m._id} value={m._id}>
                      {m.name} ({m.role})
                    </option>
                  ))}
                </select>
              ) : (
                <span style={styles.assignName}>
                  {task.assignedTo?.name || 'Unassigned'}
                </span>
              )}
            </div>

            {/* Status dropdown */}
            <div style={styles.statusRow}>
              <span style={styles.assignLabel}>📌 Status:</span>
              <select
                style={styles.statusSelect}
                value={task.status}
                onChange={(e) => handleStatusChange(task._id, e.target.value)}
              >
                <option value="todo">📋 To Do</option>
                <option value="in-progress">⚙️ In Progress</option>
                <option value="done">✅ Done</option>
              </select>
            </div>
          </div>
        ))}
      </div>

      {tasks.length === 0 && (
        <div style={styles.empty}>
          <p>No tasks yet. Add one above!</p>
        </div>
      )}
    </div>
  );
};

const styles = {
  container: { maxWidth: '900px', margin: '0 auto' },
  heading: { color: '#1e293b', marginBottom: '8px' },
  summaryBar: {
    display: 'flex', gap: '16px', marginBottom: '24px',
    background: '#1e293b', borderRadius: '12px', padding: '16px 24px',
  },
  summaryItem: { textAlign: 'center', flex: 1 },
  summaryNum: { display: 'block', fontSize: '28px', fontWeight: 'bold', color: 'white' },
  summaryLabel: { fontSize: '12px', color: '#94a3b8' },
  form: {
    background: 'white', padding: '24px', borderRadius: '12px',
    boxShadow: '0 2px 10px rgba(0,0,0,0.08)', marginBottom: '24px',
  },
  formTitle: { margin: '0 0 16px', color: '#1e293b' },
  formGrid: { display: 'flex', flexDirection: 'column', gap: '10px', marginBottom: '16px' },
  input: {
    padding: '10px 14px', border: '1px solid #e2e8f0',
    borderRadius: '8px', fontSize: '14px', width: '100%', boxSizing: 'border-box',
  },
  button: {
    backgroundColor: '#3b82f6', color: 'white', border: 'none',
    padding: '12px 24px', borderRadius: '8px', fontSize: '15px',
    cursor: 'pointer', width: '100%',
  },
  error: { background: '#fee2e2', color: '#dc2626', padding: '10px', borderRadius: '6px', marginBottom: '12px' },
  success: { background: '#dcfce7', color: '#16a34a', padding: '10px', borderRadius: '6px', marginBottom: '12px' },
  list: { display: 'flex', flexDirection: 'column', gap: '12px' },
  card: {
    padding: '20px', borderRadius: '12px',
    boxShadow: '0 2px 8px rgba(0,0,0,0.06)', background: 'white',
  },
  cardHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px' },
  cardActions: { display: 'flex', alignItems: 'center', gap: '8px' },
  cardTitle: { margin: '0 0 4px', color: '#1e293b', fontSize: '16px' },
  desc: { color: '#64748b', fontSize: '14px', margin: 0 },
  priorityBadge: { padding: '2px 10px', borderRadius: '20px', fontSize: '12px', fontWeight: '500' },
  deleteBtn: { background: 'none', border: 'none', cursor: 'pointer', fontSize: '16px' },
  due: { fontSize: '13px', margin: '8px 0' },
  assignRow: { display: 'flex', alignItems: 'center', gap: '10px', margin: '10px 0 6px' },
  assignLabel: { fontSize: '13px', color: '#64748b', whiteSpace: 'nowrap' },
  assignSelect: {
    padding: '5px 10px', border: '1px solid #e2e8f0',
    borderRadius: '6px', fontSize: '13px', flex: 1,
  },
  assignName: { fontSize: '13px', color: '#1e293b', fontWeight: '500' },
  statusRow: { display: 'flex', alignItems: 'center', gap: '10px', marginTop: '6px' },
  statusSelect: {
    padding: '5px 10px', border: '1px solid #e2e8f0',
    borderRadius: '6px', fontSize: '13px',
  },
  empty: { textAlign: 'center', color: '#94a3b8', padding: '40px' },
};

export default Tasks;
